async function saveExamResultToCloud(result){if(!fb||!authUser||!result?.id)return;try{let clean=JSON.parse(JSON.stringify(result));await fb.firestore().collection("users").doc(authUser.uid).collection("examResults").doc(String(result.id)).set(clean)}catch(error){console.warn("Could not save exam result to account:",error)}}
async function syncExamResultsWithCloud(){if(!fb||!authUser)return;try{let collection=fb.firestore().collection("users").doc(authUser.uid).collection("examResults"),snapshot=await collection.limit(100).get(),cloud=snapshot.docs.map(doc=>({id:doc.id,...doc.data()})),cloudIds=new Set(cloud.map(result=>String(result.id))),local=data.history.slice(0,100),batch=fb.firestore().batch(),writes=0;local.forEach(result=>{if(!cloudIds.has(String(result.id))){batch.set(collection.doc(String(result.id)),JSON.parse(JSON.stringify(result)));writes++}});if(writes)await batch.commit();let merged=new Map();cloud.forEach(result=>merged.set(String(result.id),result));local.forEach(result=>merged.set(String(result.id),result));data.history=[...merged.values()].sort((a,b)=>new Date(b.date||0)-new Date(a.date||0)).slice(0,100);save();if(!$("#dashboardView")?.classList.contains("hidden"))renderDashboard()}catch(error){console.warn("Could not sync saved exam results:",error)}}
function firebaseConfigured(){return window.firebase&&window.FIREBASE_CONFIG&&!String(window.FIREBASE_CONFIG.apiKey||"").includes("PASTE_")}
function callFn(name,data={}){if(!functionsApi)throw new Error("Firebase Functions are not ready.");return functionsApi.httpsCallable(name)(data).then(r=>r.data)}
