function setAuthGate(show){let gate=$("#authGate");if(!gate)return;gate.classList.toggle("hidden",!show);gate.style.display=show?"grid":"none";gate.setAttribute("aria-hidden",show?"false":"true");$("#signOutButton")?.classList.toggle("hidden",show)}
function renderAccount(){let email=authUser?.email||"",isAdmin=ADMIN_EMAILS.includes(email.toLowerCase()),isPremium=account?.accountType==="premium"||account?.premiumStatus==="approved"||isAdmin;$("#adminNav")?.classList.toggle("hidden",!isAdmin);$("#accountBox")?.classList.toggle("hidden",!authUser);$("#accountEmail").textContent=email;$("#accountStatus").textContent=isPremium?"Premium account":"Basic account";$("#upgradePremium")?.classList.toggle("hidden",isPremium)}
