function renderAdminLists(users,requests,usage,approve){let pending=[...requests],pendingIds=new Set(pending.map(r=>r.uid||r.id));users.forEach(u=>{let uid=u.uid||u.id;if(uid&&!pendingIds.has(uid)&&u.premiumStatus==="requested"&&u.accountType!=="premium"){pending.push({...u,uid,status:"requested"});pendingIds.add(uid)}});$("#adminStats").innerHTML=stats([["Users",users.length],["Premium requests",pending.length],["Usage 24h",countUsage(usage,86400000)],["Usage 30d",countUsage(usage,2592000000)]]);$("#premiumRequests").innerHTML=pending.length?pending.map(r=>`<div class="history-row"><strong>${escapeHtml(r.email||"")}</strong><span>${escapeHtml(r.displayName||r.status||"requested")}</span><button class="soft" data-approve="${escapeHtml(r.uid||r.id)}">Approve</button></div>`).join(""):`<p class="fine-print">No pending requests.</p>`;$("#adminUsers").innerHTML=users.map(u=>{let uid=u.uid||u.id,needsApproval=u.premiumStatus==="requested"&&u.accountType!=="premium";return`<div class="history-row"><strong>${escapeHtml(u.email||"")}</strong><span>${escapeHtml(u.accountType||"basic")} · ${escapeHtml(u.premiumStatus||"none")}</span>${needsApproval?`<button class="soft" data-approve="${escapeHtml(uid)}">Approve</button>`:`<span>${u.lastLoginAt?.seconds?new Date(u.lastLoginAt.seconds*1000).toLocaleDateString():""}</span>`}</div>`}).join("");$$("[data-approve]").forEach(b=>b.onclick=async()=>{await approve(b.dataset.approve);toast("Premium approved.");renderAdmin()})}
