      let replacement;
      while(online.length&&!replacement){let candidate=online.shift(),key=questionKey(candidate);if(!existing.has(key)){replacement=candidate;existing.add(key)}}
      if(replacement){exam.questions[i]=replacement;replacements.push(replacement)}
